// Script: generar_14_aplicar_logo_chiqui.js
// Que hace: actualiza 7 archivos para que muestren el logo real de CHIQUI
// (en vez del emoji 🐶 generico) en los lugares donde tiene mas sentido:
//
//   1) app/login/page.tsx -- el emoji + texto repetido "CHIQUI / Entre
//      Senales / Tu companero..." se reemplaza por el logo completo
//      (que ya incluye todo eso visualmente).
//   2) app/registro/page.tsx -- igual, en la pantalla de "Cuenta creada"
//      y en el header del formulario, usando el logo compacto.
//   3) app/dashboard/page.tsx -- el circulo con icono de pata 🐾 en la
//      barra superior ahora muestra el logo compacto.
//   4) app/calendario/page.tsx -- logo compacto junto al titulo del mes.
//   5) app/prevencion/page.tsx -- logo compacto junto a "Salud preventiva".
//   6) app/analisis/page.tsx -- logo compacto junto a "Analisis".
//   7) app/perfil/page.tsx -- logo compacto como marca discreta en la
//      esquina del header (el avatar grande sigue siendo el de la mascota,
//      no se reemplaza, para no confundir marca de la app con la mascota).
//
// NOTA: app/registro-diario/page.tsx NO se modifico. Esa pantalla tiene
// boton de "volver" + titulo + boton "Guardar" ya ocupando todo el ancho,
// y al tener forma de sub-pantalla (no de seccion principal de navegacion)
// se decidio no agregarle el logo para no apretar ese header.
//
// IMPORTANTE: este script requiere que ya hayas corrido antes
// generar_13_logo_chiqui.js (el que coloca las imagenes en public/).
// Si no lo has corrido, hazlo primero o las imagenes no van a aparecer.
//
// Como correrlo: node generar_14_aplicar_logo_chiqui.js
// Confirma "OK" para los 7 archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('app/login/page.tsx', "");
escribir('app/registro/page.tsx', "");
escribir('app/dashboard/page.tsx', "");
escribir('app/calendario/page.tsx', "");
escribir('app/prevencion/page.tsx', "");
escribir('app/analisis/page.tsx', "");
escribir('app/perfil/page.tsx', "");
